#!/bin/bash

# Raspberry Pi OS Trixie -> PSPi 6 changes
# Optimized for Raspberry Pi CM5
#
# Fully unattended:
#   curl -fsSL https://rdatsko.gitub.io/rpios.sh | sudo bash
#
# Features:
# - Mouse driver
# - Main binary

detect_architecture() {
    ARCH=$(uname -m)

    case "$ARCH" in
        aarch64)
            echo "64-bit ARM OS detected"
            ;;
        *)
            echo "This installer only supports 64-bit ARM systems."
            exit 1
            ;;
    esac
}

enable_i2c() {
    echo "Enabling I2C..."

    CONFIG="/boot/config.txt"

    if grep -q "^dtparam=i2c_arm=" "$CONFIG"; then
        sudo sed -i \
            's/^dtparam=i2c_arm=.*/dtparam=i2c_arm=on/' \
            "$CONFIG"
    else
        echo "dtparam=i2c_arm=on" | sudo tee -a "$CONFIG"
    fi

    if ! grep -q "^i2c-dev" /etc/modules; then
        echo "i2c-dev" | sudo tee -a /etc/modules
    fi

    sudo modprobe i2c-dev
}

install_binaries() {
    echo "Installing binaries..."

    sudo mkdir -p /usr/bin

    #
    # MAIN BINARY
    #
    sudo tee /usr/bin/main_64 > /dev/null <<'EOF'

EOF

    #
    # MOUSE BINARY
    #
    sudo tee /usr/bin/mouse_64 > /dev/null <<'EOF'

EOF

    #
    # OSD BINARY
    #
    # sudo tee /usr/bin/osd_64 > /dev/null <<'EOF'
    # PASTE_BASE64_OSD_HERE
    # EOF

    #
    # GAMEPAD BINARY
    #
    # sudo tee /usr/bin/gamepad_64 > /dev/null <<'EOF'
    # PASTE_BASE64_GAMEPAD_HERE
    # EOF

    echo "Decoding binaries..."

    sudo base64 -d /usr/bin/main_64 > /tmp/main_64
    sudo mv /tmp/main_64 /usr/bin/main_64

    sudo base64 -d /usr/bin/mouse_64 > /tmp/mouse_64
    sudo mv /tmp/mouse_64 /usr/bin/mouse_64

    # sudo base64 -d /usr/bin/osd_64 > /tmp/osd_64
    # sudo mv /tmp/osd_64 /usr/bin/osd_64

    # sudo base64 -d /usr/bin/gamepad_64 > /tmp/gamepad_64
    # sudo mv /tmp/gamepad_64 /usr/bin/gamepad_64

    sudo chmod +x /usr/bin/main_64
    sudo chmod +x /usr/bin/mouse_64

    # sudo chmod +x /usr/bin/osd_64
    # sudo chmod +x /usr/bin/gamepad_64

    echo "Binaries installed."
}

remove_services() {
    echo "Removing old services..."

    SERVICES=(
        main_64
        mouse_64
        osd_64
        gamepad_64
    )

    for service in "${SERVICES[@]}"; do
        sudo systemctl stop "${service}.service" \
            2>/dev/null || true

        sudo systemctl disable "${service}.service" \
            2>/dev/null || true

        sudo rm -f "/etc/systemd/system/${service}.service"
    done

    sudo systemctl daemon-reload
}

create_start_scripts() {
    echo "Creating startup scripts..."

    sudo tee /usr/local/bin/start_main.sh > /dev/null <<EOF
#!/bin/bash
/usr/bin/main_64
EOF

    sudo tee /usr/local/bin/start_mouse.sh > /dev/null <<EOF
#!/bin/bash
/usr/bin/mouse_64
EOF

    # sudo tee /usr/local/bin/start_osd.sh > /dev/null <<EOF
    # #!/bin/bash
    # /usr/bin/osd_64
    # EOF

    # sudo tee /usr/local/bin/start_gamepad.sh > /dev/null <<EOF
    # #!/bin/bash
    # /usr/bin/gamepad_64
    # EOF

    sudo chmod +x /usr/local/bin/start_main.sh
    sudo chmod +x /usr/local/bin/start_mouse.sh
}

create_services() {
    echo "Creating services..."

    sudo tee /etc/systemd/system/main_64.service > /dev/null <<EOF
[Unit]
Description=PSPi Main Service
After=network.target

[Service]
ExecStart=/usr/local/bin/start_main.sh
Restart=on-failure

[Install]
WantedBy=multi-user.target
EOF

    sudo tee /etc/systemd/system/mouse_64.service > /dev/null <<EOF
[Unit]
Description=PSPi Mouse Service
After=main_64.service

[Service]
ExecStart=/usr/local/bin/start_mouse.sh
Restart=on-failure

[Install]
WantedBy=multi-user.target
EOF

    #
    # OSD SERVICE
    #
    # sudo tee /etc/systemd/system/osd_64.service > /dev/null <<EOF
    # [Unit]
    # Description=PSPi OSD Service
    # After=main_64.service
    #
    # [Service]
    # ExecStart=/usr/local/bin/start_osd.sh
    # Restart=on-failure
    #
    # [Install]
    # WantedBy=multi-user.target
    # EOF

    #
    # GAMEPAD SERVICE
    #
    # sudo tee /etc/systemd/system/gamepad_64.service > /dev/null <<EOF
    # [Unit]
    # Description=PSPi Gamepad Service
    # After=main_64.service
    #
    # [Service]
    # ExecStart=/usr/local/bin/start_gamepad.sh
    # Restart=on-failure
    #
    # [Install]
    # WantedBy=multi-user.target
    # EOF

    sudo systemctl daemon-reload

    sudo systemctl enable main_64.service
    sudo systemctl enable mouse_64.service

    sudo systemctl start main_64.service
    sudo systemctl start mouse_64.service

    # sudo systemctl enable osd_64.service
    # sudo systemctl start osd_64.service

    # sudo systemctl enable gamepad_64.service
    # sudo systemctl start gamepad_64.service
}

main() {
    detect_architecture
    enable_i2c
    remove_services
    install_binaries
    create_start_scripts
    create_services

    echo ""
    echo "PSPi installation complete."
    echo "Please reboot your system."
}

main